windowclass.script:
			function onDrop(x, y, draginfo)
				if draginfo.isType("shortcut") then
					local sClass, sRecord = draginfo.getShortcutData();

					if StringManager.contains({"reference_profession", "reference_race" }, sClass) then
						CharManager.addInfoDB(getDatabaseNode(), sClass, sRecord);
						return true;
					end
				end
			end

combobox_labeled_RMC.script:
					function onInit()
						super.onInit();
						
						Module.onModuleLoad = ModuleLoadUnload;
						Module.onModuleUnload = ModuleLoadUnload;
						
						ModuleLoadUnload();
					end
					
					function ModuleLoadUnload()
						getRaceLink();
						clear();
						addItems(Rules_Races.List());
					end

					function onValueChanged()
						getRaceLink();
					end
					
					function getRaceLink()
						local sCharNode = DB.getPath(DB.getParent(getDatabaseNode()));
						Rules_Races.SetRaceLink(getValue(), sCharNode);
					end

linkfield.script:
function onInit()
	onValueChanged();
end

function onValueChanged()
	local nodeChar = window.getDatabaseNode();
	if isEmpty() then
		setVisible(false);
		Rules_PC.ClearRace(nodeChar);
	else
		setVisible(true);
	end
	local _, sRaceNodeName = getValue();
	local nodeRace = DB.findNode(sRaceNodeName);
	if nodeRace then
		Rules_PC.SetRace(nodeChar, nodeRace);
	end
end

number_labeled.script:
					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						refresh();
					end

					function onValueChanged()
						refresh();
					end
					
					function refresh()
						local nodeChar = window.getDatabaseNode();
						window.max_pp.setValue(Rules_PC.PowerPoints(nodeChar));
					end

					function onInit()
						super.onInit();
						local sLevelPath = DB.getPath(window.level.getDatabaseNode());
						DB.addHandler(sLevelPath, "onUpdate", refresh);
						refresh();
					end

					function onClose()
						local sLevelPath = DB.getPath(window.level.getDatabaseNode());
						DB.removeHandler(sLevelPath, "onUpdate", refresh);
					end

					function refresh()
						local nLevel = window.level.getValue();
						setValue(Rules_PC.NextLevelXP(nLevel));
					end

string_labeled.script:
function onValueChanged()
	local charNode = window.getDatabaseNode();
	Rules_PC.SetBaseMoveRate(charNode);
end

windowlist.script:
					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						--[[ load the stat list ]]
						local statList = Rules_Stats.List();
						for i = 1, #statList do
							addEntry(statList[i].name, statList[i].label, statList[i].displayname, statList[i].devStat, statList[i].order);
						end
						--[[ force a re-sort ]]
						applySort();
					end

					function addEntry(name, label, displayname, dev, order)
						local node = DB.getChild(getDatabaseNode(), name);
						local win;
						if not node then
							node = DB.createChild(getDatabaseNode(), name);
						end
						for i,w in ipairs(getWindows()) do
							if DB.getName(w.getDatabaseNode())==name then
								win = w;
							end
						end
						if win then
							win.abbr.setValue(label);
							win.label.setValue(displayname);
							win.label.setTooltipText("Drag or double click to roll a " .. win.label.getValue() .. " stat check");
							win.total.setTooltipText("Drag or double click to add the " .. win.label.getValue() .. " stat total bonus to the Modifier Stack");
							win.order.setValue(order);
						end
					end

					function onSortCompare(w1, w2)
						return (w1.order.getValue() > w2.order.getValue());
					end

row_heading.script:
function action(draginfo)
	local charNode = window.getDatabaseNode();
	local rActor = ActorManager.resolveActor(charNode);
	local sSkillName = ActionSkill.MovementMM;
	local nSkillMod = 0;
	local nSkillType = ActionSkill.MM;
	ActionSkill.performRoll(draginfo, rActor, sSkillName, nSkillMod, nSkillType);
	return true;
end
function onDragStart(button, x, y, draginfo)
	return action(draginfo);
end
function onDoubleClick(x,y)
	return action();
end

					function action(draginfo)
