number_readonly.script:
					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						DB.addHandler(DB.getPath(window.getDatabaseNode(), "abilities.constitution.temp_current"), "onUpdate", updateExhaustionTotal);
						DB.addHandler(DB.getPath(window.getDatabaseNode(), "exhaustion_misc"), "onUpdate", updateExhaustionTotal);
						
						updateExhaustionTotal();
						onValueChanged();
					end

					function onValueChanged()
						if getValue() < window.used_exhaustion.getValue() then
							window.used_exhaustion.setColor(ColorManager.getUIColor("field_error"));
						else
							window.used_exhaustion.setColor(nil);
						end
					end

					function updateExhaustionTotal()
						local node = window.getDatabaseNode();
						local nValue = DB.getValue(node, "abilities.constitution.temp_current", 0);
						nValue = nValue + DB.getValue(node, "exhaustion_misc", 0);
						setValue(nValue);
					end

number_boxed.script:
					function onValueChanged()
						if getValue() < 0 or getValue() > window.max_exhaustion.getValue() then
							setColor(ColorManager.getUIColor("field_error"));
						else
							setColor(nil);
						end
					end

					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						onValueChanged();
					end

					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						onValueChanged();
						OptionsManager.registerCallback("CCHP", refresh);
						refresh();
					end

					function onClose()
						OptionsManager.unregisterCallback("CCHP", refresh);
					end

					function onValueChanged()
						if getValue() < window.damage.getValue() then
							window.damage.setColor(ColorManager.getUIColor("field_error"));
						else
							window.damage.setColor(nil);
						end
					end

					function refresh()
						if string.lower(OptionsManager.getOption("CCHP")) == string.lower(Interface.getString("option_val_on")) then
							setValue(Rules_PC.Hits(window.getDatabaseNode()));
							setReadOnly(true);
							setFrame("fieldlight",4,4,4,4)
						else
							setReadOnly(false);
							setFrame("fielddark",4,4,4,4)
						end
					end

					function onValueChanged()
						if getValue() < 0 or getValue() > window.max_hits.getValue() then
							setColor(ColorManager.getUIColor("field_error"));
						else
							setColor(nil);
						end
					end

					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						onValueChanged();
					end

