number_boxed.script:
					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						OptionsManager.registerCallback("CCPP", refresh);
						OptionsManager.registerCallback("CL01", refresh);
						OptionsManager.registerCallback("CL16", refresh);
						OptionsManager.registerCallback("SL04", refresh);
						OptionsManager.registerCallback("RC44P", refresh);
						OptionsManager.registerCallback("RC48P", refresh);

						local nodeChar = window.getDatabaseNode();
						local sLevelPath = DB.getPath(nodeChar, "level");
						local sRealmPath = DB.getPath(nodeChar, "realm");
						local sEmpathyPath = DB.getPath(nodeChar, "abilities.empathy.temp_current");
						local sIntuitionPath = DB.getPath(nodeChar, "abilities.intuition.temp_current");
						local sPresencePath = DB.getPath(nodeChar, "abilities.presence.temp_current");
						local sPPMultPath = DB.getPath(nodeChar, "pp.mult");
						DB.addHandler(sLevelPath, "onIntegrityChange", onUpdate);
						DB.addHandler(sRealmPath, "onUpdate", onUpdate);
						DB.addHandler(sEmpathyPath, "onUpdate", onUpdate);
						DB.addHandler(sIntuitionPath, "onUpdate", onUpdate);
						DB.addHandler(sPresencePath, "onUpdate", onUpdate);
						DB.addHandler(sPPMultPath, "onUpdate", onUpdate);

						onValueChanged();
						refresh();
					end

					function onClose()
						OptionsManager.unregisterCallback("CCPP", refresh);
						OptionsManager.unregisterCallback("CL01", refresh);
						OptionsManager.unregisterCallback("CL16", refresh);
						OptionsManager.unregisterCallback("SL04", refresh);
						OptionsManager.unregisterCallback("RC44P", refresh);
						OptionsManager.unregisterCallback("RC48P", refresh);
					end

					function onValueChanged()
						if getValue() < window.used_pp.getValue() then
							window.used_pp.setColor(ColorManager.getUIColor("field_error"));
						else
							window.used_pp.setColor(nil);
						end
					end

					function onUpdate()
						refresh();
					end

					function refresh()
						if string.lower(OptionsManager.getOption("CCPP")) == string.lower(Interface.getString("option_val_on")) then
							setValue(Rules_PC.PowerPoints(window.getDatabaseNode()));
							setReadOnly(true);
							setFrame("fieldlight",4,4,4,4)
						else
							setReadOnly(false);
							setFrame("fielddark",4,4,4,4)
						end
					end

