windowlist.script:
					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						--[[ load the stat list ]]
						local statList = Rules_Stats.List();
						for i = 1, #statList do
							addEntry(statList[i].name, statList[i].label, statList[i].displayname, statList[i].devStat, statList[i].order);
						end
						--[[ force a re-sort ]]
						applySort();
					end

					function addEntry(name, label, displayname, dev, order)
						local node = DB.getChild(getDatabaseNode(), name);
						local win;
						if not node then
							node = DB.createChild(getDatabaseNode(), name);
						end
						for i,w in ipairs(getWindows()) do
							if DB.getName(w.getDatabaseNode())==name then
								win = w;
							end
						end
						if win then
							win.abbr.setValue(label);
							win.label.setValue(displayname);
							win.label.setTooltipText("Drag or double click to roll a " .. win.label.getValue() .. " stat check");
							win.total.setTooltipText("Drag or double click to add the " .. win.label.getValue() .. " stat total bonus to the Modifier Stack");
							win.order.setValue(order);
							if dev == true then
								win.dev.setValue(1);
							else
								win.dev.setValue(0);
							end
						end
					end

					function onSortCompare(w1, w2)
						return (w1.order.getValue() > w2.order.getValue());
					end

					function setDPs()
						local charNode = window.getDatabaseNode();
						window.dptotal.setValue(Rules_PC.TotalDP(charNode));
					end

windowclass.script:
			function onInit()
				OptionsManager.registerCallback("RC44B", refresh);
				OptionsManager.registerCallback("RC48B", refresh);

				local node = getDatabaseNode();
				DB.addHandler(DB.getPath(node, "temp"), "onUpdate", self.refresh);
				DB.addHandler(DB.getPath(node, "damage"), "onUpdate", self.refresh);
				self.refresh();
			end

			function onClose()
				OptionsManager.unregisterCallback("RC44B", refresh);
				OptionsManager.unregisterCallback("RC48B", refresh);
			end

			function refresh()
				local statNode = getDatabaseNode();
				temp_current.setValue(temp.getValue() - damage.getValue());
				DB.setValue(statNode, "bonus", "number", Rules_Stats.Bonus(temp_current.getValue()));
			end

