windowclass.script:
			function onInit()
				OptionsManager.registerCallback("CL111", refresh);
				OptionsManager.registerCallback("CL112", refresh);
				OptionsManager.registerCallback("RC44B", refresh);
				OptionsManager.registerCallback("RC44D", refresh);
				OptionsManager.registerCallback("RC48B", refresh);
				OptionsManager.registerCallback("RC48D", refresh);
				OptionsManager.registerCallback("RC552", refresh);

				local node = getDatabaseNode();
				DB.addHandler(DB.getPath(node, "temp"), "onUpdate", self.refresh);
				DB.addHandler(DB.getPath(node, "race"), "onUpdate", self.refresh);
				DB.addHandler(DB.getPath(node, "special"), "onUpdate", self.refresh);
				DB.addHandler(DB.getPath(node, "damage"), "onUpdate", self.refresh);
				self.refresh();
			end

			function onClose()
				OptionsManager.unregisterCallback("CL111", refresh);
				OptionsManager.unregisterCallback("CL112", refresh);
				OptionsManager.unregisterCallback("RC44B", refresh);
				OptionsManager.unregisterCallback("RC44D", refresh);
				OptionsManager.unregisterCallback("RC48B", refresh);
				OptionsManager.unregisterCallback("RC48D", refresh);
				OptionsManager.unregisterCallback("RC552", refresh);
			end

			function refresh()
				local statNode = getDatabaseNode();
				temp_current.setValue(temp.getValue() - damage.getValue());
				DB.setValue(statNode, "bonus", "number", Rules_Stats.Bonus(temp_current.getValue()));
				if string.lower(OptionsManager.getOption("CL112")) == string.lower(Interface.getString("option_val_off")) then 
					local nTemp = temp.getValue();
					local nTotalBonus = total.getValue();
					dp.setValue(Rules_Stats.DPs(nTemp, nTotalBonus));
					
					if string.lower(OptionsManager.getOption("RC552")) == string.lower(Interface.getString("option_val_off")) then 
						if dev.getValue() == 1 then
							dp.setVisible(true);
						else
							dp.setVisible(false);
						end
					else
						dp.setVisible(true);
					end
				else
					dp.setVisible(false);
				end

				windowlist.setDPs();
			end

