local statNode = nil;
function onInit()
	refresh();
end
function refresh()
	if statNode then
		DB.setValue(getDatabaseNode(), "stat", "number", DB.getValue(statNode));
	end
end
function setStat(name)
	if name then
		statNode = DB.getChild(windowlist.window.getDatabaseNode(), "abilities." .. name .. ".total");
		if statNode then
			DB.addHandler(DB.getPath(statNode), "onUpdate", self.refresh);
		end
		refresh();
	end
end

