windowclass.script:
local statNode = nil;
function onInit()
	refresh();
end
function refresh()
	if statNode then
		DB.createChild(getDatabaseNode(), "stat", "number", statNode.getValue())
	end
end
function setStat(name)
	statNode = DB.getChild(windowlist.window.getDatabaseNode(), "abilities." .. name .. ".total");
	if statNode then
		DB.addHandler(DB.getPath(statNode), "onUpdate", self.refresh);
		for i, onestat in pairs(Rules_Stats.List()) do
			if onestat.name == name then
				abbr.setValue(onestat.label);
			end
		end
	end
	refresh();
end

