number_readonly.script:
					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						
						local nodeChar = window.getDatabaseNode();
						OptionsManager.registerCallback("CEMV", refresh);
						DB.addHandler(DB.getPath(Rules_PC.BMRStatNode(nodeChar)), "onUpdate", refresh);
						DB.addHandler(DB.getPath(nodeChar, "bmrrace"), "onUpdate", refresh);
						DB.addHandler(DB.getPath(nodeChar, "bmrencumbrance"), "onUpdate", refresh);
						DB.addHandler(DB.getPath(nodeChar, "bmrmisc"), "onUpdate", refresh);
						DB.addHandler(DB.getPath(nodeChar, "dbpen"), "onUpdate", refresh);
						
						refresh();
					end
					function onClose()
						local nodeChar = window.getDatabaseNode();
						OptionsManager.unregisterCallback("CEMV", refresh);
						DB.removeHandler(DB.getPath(Rules_PC.BMRStatNode(nodeChar)), "onUpdate", refresh);
						DB.removeHandler(DB.getPath(nodeChar, "bmrrace"), "onUpdate", refresh);
						DB.removeHandler(DB.getPath(nodeChar, "bmrencumbrance"), "onUpdate", refresh);
						DB.removeHandler(DB.getPath(nodeChar, "bmrmisc"), "onUpdate", refresh);
						DB.removeHandler(DB.getPath(nodeChar, "dbpen"), "onUpdate", refresh);
					end

					function refresh()
						local nodeChar = window.getDatabaseNode();
						local nBMRTotal, nBMRStat, bShowBMRStatInfo, bShowBMREncumbranceInfo = Rules_PC.GetTotalBMR(nodeChar);
						
						setValue(nBMRTotal);
						window.bmrstat.setValue(nBMRStat);
						window.bmrstat_info.setVisible(bShowBMRStatInfo);	
						window.bmrencumbrance_off_info.setVisible(bShowBMREncumbranceInfo);
						
						if string.lower(OptionsManager.getOption("CEMV")) == string.lower(Interface.getString("option_val_on")) then 
							window.bmrencumbrance.setVisible(true);
							window.bmrencumbrance_off.setVisible(false);
							window.bmrencumbrance_off_info.setVisible(false);
						else
							window.bmrencumbrance.setVisible(false);
							window.bmrencumbrance_off.setVisible(true);
						end
					end

