number_boxed.script:
function onInit()
	local nodeChar = window.getDatabaseNode();
	DB.addHandler(DB.getPath(nodeChar, "exhaustion_total"), "onUpdate", updatePenaltyInfo);
	updatePenaltyInfo();
end

function onValueChanged()
	updatePenaltyInfo();
end

function updatePenaltyInfo()
	local nodeChar = window.getDatabaseNode();
	local sDescription, nPenalty = Rules_Modifiers.Exhaustion(nodeChar);
	window.exhaustion_penalty.setValue(nPenalty);
	window.exhaustion_penalty_description.setValue(sDescription);						
end
